module RefModule(clk, rst, set, d, q, qn);input clk, rst, set, d;
output q, qn;
  wire _tap_clk = clk & {1{1'b1}};

reg q, qn;

always @(posedge clk or posedge rst or posedge set) begin
    if (rst) begin
        q <= 0;
        qn <= 1;
    end
    else if (set) begin
        q <= 1;
        qn <= 0;
    end
    else begin
        q <= d;
        qn <= ~d;
    end
end

endmodule
